function getTrInflectedReplacement(sentence, targetStem, otherStem) {
  const words = sentence.split(/\s+/);
  let targetWord = "";
  for (const w of words) {
    const cleanW = w.toLowerCase().replace(/[.,\/#!$%\^&\*;:{}=\-_`~()?]/g,"");
    if (cleanW.includes(targetStem.toLowerCase())) {
      targetWord = w;
      break;
    }
  }
  
  if (!targetWord) {
    return sentence.replace(targetStem, otherStem);
  }
  
  const targetWordClean = targetWord.replace(/[.,\/#!$%\^&\*;:{}=\-_`~()?]/g,"");
  const idx = targetWordClean.toLowerCase().indexOf(targetStem.toLowerCase());
  if (idx === -1) {
    return sentence.replace(targetStem, otherStem);
  }
  
  const suffix = targetWordClean.slice(idx + targetStem.length).toLowerCase();
  
  const getLastVowel = (w) => {
    const vowels = "aıoueiöü";
    for (let i = w.length - 1; i >= 0; i--) {
      if (vowels.includes(w[i].toLowerCase())) return w[i].toLowerCase();
    }
    return 'e';
  };
  
  const isVoicelessConsonant = (char) => {
    return "fstkçşhp".includes(char.toLowerCase());
  };
  
  let replacedWord = otherStem;
  
  if (suffix.endsWith("dedir") || suffix.endsWith("tedir") || suffix.endsWith("dadır") || suffix.endsWith("tadır") || suffix.endsWith("ndedir")) {
    if (otherStem.toLowerCase() === "deney tüpü") {
      replacedWord = "deney tüpündedir";
    } else {
      const lastV = getLastVowel(otherStem);
      const lastC = otherStem[otherStem.length - 1];
      const isBack = "aıou".includes(lastV);
      const isVoiceless = isVoicelessConsonant(lastC);
      const loc = isBack ? (isVoiceless ? "ta" : "da") : (isVoiceless ? "te" : "de");
      const cop = isBack ? "dır" : "dir";
      replacedWord = otherStem + loc + cop;
    }
  } else if (suffix.endsWith("mın") || suffix.endsWith("min") || suffix.endsWith("ımın") || suffix.endsWith("imin") || suffix.endsWith("umun") || suffix.endsWith("ümün")) {
    const lastV = getLastVowel(otherStem);
    const lastC = otherStem[otherStem.length - 1];
    const isVowel = "aıoueiöü".includes(lastC.toLowerCase());
    if (isVowel) {
      replacedWord = otherStem + ("aıou".includes(lastV) ? "mın" : "min");
    } else {
      if ("aı".includes(lastV)) replacedWord = otherStem + "ımın";
      else if ("ei".includes(lastV)) replacedWord = otherStem + "imin";
      else if ("ou".includes(lastV)) replacedWord = otherStem + "umun";
      else replacedWord = otherStem + "ümün";
    }
  } else if (suffix.endsWith("dendir") || suffix.endsWith("tandır") || suffix.endsWith("dandır") || suffix.endsWith("tendir")) {
    const lastV = getLastVowel(otherStem);
    const lastC = otherStem[otherStem.length - 1];
    const isBack = "aıou".includes(lastV);
    const isVoiceless = isVoicelessConsonant(lastC);
    const abl = isBack ? (isVoiceless ? "tan" : "dan") : (isVoiceless ? "ten" : "den");
    const cop = isBack ? "dır" : "dir";
    replacedWord = otherStem + abl + cop;
  } else {
    if (targetWord[0] === targetWord[0].toUpperCase()) {
      replacedWord = otherStem.charAt(0).toUpperCase() + otherStem.slice(1);
    } else {
      replacedWord = otherStem;
    }
  }
  
  const prefixPunct = targetWord.match(/^[^a-zA-ZçıüşöğİÇŞÖĞü]+/);
  const suffixPunct = targetWord.match(/[^a-zA-ZçıüşöğİÇŞÖĞü]+$/);
  
  let finalWord = (prefixPunct ? prefixPunct[0] : "") + replacedWord + (suffixPunct ? suffixPunct[0] : "");
  return sentence.replace(targetWord, finalWord);
}

function buildCustom15QuestionExercises(sentences, unitId, lessonId, exId, offset) {
  const qList = [];
  const shuffle = (arr) => [...arr].sort(() => 0.5 - Math.random());
  
  const slice = [];
  for (let i = 0; i < 15; i++) {
    const idx = (offset + i) % sentences.length;
    slice.push(sentences[idx]);
  }

  // 1. Matching (2 questions)
  qList.push({
    id: `u${unitId}l${lessonId}_ex${exId}_match1`,
    type: "matching",
    prompt: "Kelimeleri Türkçe karşılıklarıyla eşleştirin.",
    pairs: slice.slice(0, 4).map(s => ({
      left: s.trWord,
      right: s.word
    }))
  });

  qList.push({
    id: `u${unitId}l${lessonId}_ex${exId}_match2`,
    type: "matching",
    prompt: "Kelimeleri Türkçe karşılıklarıyla eşleştirin.",
    pairs: slice.slice(4, 8).map(s => ({
      left: s.trWord,
      right: s.word
    }))
  });

  const getMcDistractors = (s, isTr) => {
    const targetVal = isTr ? s.tr : s.en;
    const distractors = [];
    const verb = s.word;
    const trVerb = s.trWord;

    if (!isTr && verb && s.en.includes(verb)) {
      const parts = s.en.split(verb);
      if (parts.length === 2) {
        const subj = parts[0].trim();
        let obj = parts[1].trim();
        const hasPeriod = obj.endsWith(".");
        if (hasPeriod) obj = obj.slice(0, -1).trim();

        // 1. Swap Subject and Object (Semantic Reversal)
        const cap = str => str.charAt(0).toUpperCase() + str.slice(1);
        const decap = str => str.charAt(0).toLowerCase() + str.slice(1);
        if (subj.toLowerCase() !== obj.toLowerCase()) {
          const swapped = cap(obj) + " " + verb + " " + decap(subj) + (hasPeriod ? "." : "");
          if (swapped !== s.en && !distractors.includes(swapped)) {
            distractors.push(swapped);
          }
        }

        // 2. Alter word order of Subject if complex (length >= 3 words)
        const subjWords = subj.split(/\s+/);
        if (subjWords.length >= 3) {
          const idx = subjWords.length > 3 ? 2 : 1;
          const temp = subjWords[idx];
          subjWords[idx] = subjWords[idx+1];
          subjWords[idx+1] = temp;
          const alteredSubj = subjWords.join(" ");
          const distVal = alteredSubj + " " + verb + " " + obj + (hasPeriod ? "." : "");
          if (distVal !== s.en && !distractors.includes(distVal)) {
            distractors.push(distVal);
          }
        }

        // 3. Alter word order of Object if complex
        const objWords = obj.split(/\s+/);
        if (objWords.length >= 3) {
          const idx = objWords.length > 3 ? 2 : 1;
          const temp = objWords[idx];
          objWords[idx] = objWords[idx+1];
          objWords[idx+1] = temp;
          const alteredObj = objWords.join(" ");
          const distVal = subj + " " + verb + " " + alteredObj + (hasPeriod ? "." : "");
          if (distVal !== s.en && !distractors.includes(distVal)) {
            distractors.push(distVal);
          }
        }
      }
    }

    if (isTr && trVerb && s.tr.includes(trVerb)) {
      const parts = s.tr.split(trVerb);
      if (parts.length === 2) {
        const prefix = parts[0].trim();
        const suffix = parts[1].trim();
        const words = prefix.split(/\s+/);
        if (words.length >= 3) {
          const temp = words[1];
          words[1] = words[2];
          words[2] = temp;
          const alteredPrefix = words.join(" ");
          const distVal = alteredPrefix + " " + trVerb + (suffix ? " " + suffix : "");
          if (distVal !== s.tr && !distractors.includes(distVal)) {
            distractors.push(distVal);
          }
        }
        if (words.length >= 4) {
          const words2 = prefix.split(/\s+/);
          const temp = words2[2];
          words2[2] = words2[3];
          words2[3] = temp;
          const alteredPrefix = words2.join(" ");
          const distVal = alteredPrefix + " " + trVerb + (suffix ? " " + suffix : "");
          if (distVal !== s.tr && !distractors.includes(distVal)) {
            distractors.push(distVal);
          }
        }
      }
    }

    // 4. Fill remaining spots with Verb Substitution
    const others = sentences.filter(o => o.word !== s.word && o.trWord !== s.trWord);
    const shuffledOthers = shuffle(others);
    for (let i = 0; i < shuffledOthers.length; i++) {
      if (distractors.length >= 3) break;
      const other = shuffledOthers[i];
      if (isTr) {
        if (s.trWord && other.trWord && s.tr.includes(s.trWord)) {
          const distVal = getTrInflectedReplacement(s.tr, s.trWord, other.trWord);
          if (distVal !== s.tr && !distractors.includes(distVal)) {
            distractors.push(distVal);
          }
        }
      } else {
        if (s.word && other.word && s.en.includes(s.word)) {
          const distVal = s.en.replace(s.word, other.word);
          if (distVal !== s.en && !distractors.includes(distVal)) {
            distractors.push(distVal);
          }
        }
      }
    }

    // 5. Fallback
    if (distractors.length < 3) {
      const list = sentences.filter(item => (isTr ? item.tr : item.en) !== targetVal).map(item => isTr ? item.tr : item.en);
      const shuffled = shuffle([...new Set(list)]);
      for (const val of shuffled) {
        if (!distractors.includes(val)) {
          distractors.push(val);
        }
        if (distractors.length >= 3) break;
      }
    }

    while (distractors.length < 3) {
      distractors.push(isTr ? "deneme" : "test");
    }

    return distractors.slice(0, 3);
  };

  const getWbDistractors = (targetWords, isTr) => {
    const list = sentences.map(s => (isTr ? s.tr : s.en).split(/\s+/).map(w => w.replace(/[.,\/#!$%\^&\*;:{}=\-_`~()?]/g,""))).flat();
    const unique = [...new Set(list)].filter(w => !targetWords.includes(w));
    const shuffled = shuffle(unique);
    while (shuffled.length < 3) {
      shuffled.push(isTr ? "ve" : "the");
    }
    return shuffled.slice(0, 3);
  };

  // 2. Multiple Choice (4 questions)
  {
    const s = slice[8];
    const dist = getMcDistractors(s, true);
    const options = shuffle([s.tr, ...dist]);
    qList.push({
      id: `u${unitId}l${lessonId}_ex${exId}_mc_0`,
      type: "multiple-choice",
      prompt: `"${s.en}" cümlesinin Türkçe karşılığı hangisidir?`,
      options: options,
      correctIndex: options.indexOf(s.tr),
      enSentence: s.en,
      isEngToTr: true
    });
  }
  {
    const s = slice[9];
    const dist = getMcDistractors(s, true);
    const options = shuffle([s.tr, ...dist]);
    qList.push({
      id: `u${unitId}l${lessonId}_ex${exId}_mc_1`,
      type: "multiple-choice",
      prompt: `"${s.en}" cümlesinin Türkçe karşılığı hangisidir?`,
      options: options,
      correctIndex: options.indexOf(s.tr),
      enSentence: s.en,
      isEngToTr: true
    });
  }
  {
    const s = slice[10];
    const dist = getMcDistractors(s, false);
    const options = shuffle([s.en, ...dist]);
    qList.push({
      id: `u${unitId}l${lessonId}_ex${exId}_mc_2`,
      type: "multiple-choice",
      prompt: `"${s.tr}" cümlesinin İngilizce karşılığı hangisidir?`,
      options: options,
      correctIndex: options.indexOf(s.en),
      enSentence: s.en,
      isEngToTr: false
    });
  }
  {
    const s = slice[11];
    const dist = getMcDistractors(s, false);
    const options = shuffle([s.en, ...dist]);
    qList.push({
      id: `u${unitId}l${lessonId}_ex${exId}_mc_3`,
      type: "multiple-choice",
      prompt: `"${s.tr}" cümlesinin İngilizce karşılığı hangisidir?`,
      options: options,
      correctIndex: options.indexOf(s.en),
      enSentence: s.en,
      isEngToTr: false
    });
  }

  // 3. Word Bank (5 questions)
  {
    const s = slice[0];
    const targetWords = s.tr.split(/\s+/).map(w => w.replace(/[.,\/#!$%\^&\*;:{}=\-_`~()?]/g,""));
    const dist = getWbDistractors(targetWords, true);
    const words = shuffle([...targetWords, ...dist]);
    qList.push({
      id: `u${unitId}l${lessonId}_ex${exId}_wb_0`,
      type: "word-bank",
      prompt: "Cümlenin Türkçe karşılığını oluşturun:",
      translation: s.en,
      words: words,
      correctOrder: targetWords,
      enSentence: s.en,
      isEngToTr: true
    });
  }
  {
    const s = slice[1];
    const targetWords = s.tr.split(/\s+/).map(w => w.replace(/[.,\/#!$%\^&\*;:{}=\-_`~()?]/g,""));
    const dist = getWbDistractors(targetWords, true);
    const words = shuffle([...targetWords, ...dist]);
    qList.push({
      id: `u${unitId}l${lessonId}_ex${exId}_wb_1`,
      type: "word-bank",
      prompt: "Cümlenin Türkçe karşılığını oluşturun:",
      translation: s.en,
      words: words,
      correctOrder: targetWords,
      enSentence: s.en,
      isEngToTr: true
    });
  }
  {
    const s = slice[2];
    const targetWords = s.tr.split(/\s+/).map(w => w.replace(/[.,\/#!$%\^&\*;:{}=\-_`~()?]/g,""));
    const dist = getWbDistractors(targetWords, true);
    const words = shuffle([...targetWords, ...dist]);
    qList.push({
      id: `u${unitId}l${lessonId}_ex${exId}_wb_2`,
      type: "word-bank",
      prompt: "Cümlenin Türkçe karşılığını oluşturun:",
      translation: s.en,
      words: words,
      correctOrder: targetWords,
      enSentence: s.en,
      isEngToTr: true
    });
  }
  {
    const s = slice[3];
    const targetWords = s.en.split(/\s+/).map(w => w.replace(/[.,\/#!$%\^&\*;:{}=\-_`~()?]/g,""));
    const dist = getWbDistractors(targetWords, false);
    const words = shuffle([...targetWords, ...dist]);
    qList.push({
      id: `u${unitId}l${lessonId}_ex${exId}_wb_3`,
      type: "word-bank",
      prompt: "Cümlenin İngilizce karşılığını oluşturun:",
      translation: s.tr,
      words: words,
      correctOrder: targetWords,
      enSentence: s.en,
      isEngToTr: false
    });
  }
  {
    const s = slice[4];
    const targetWords = s.en.split(/\s+/).map(w => w.replace(/[.,\/#!$%\^&\*;:{}=\-_`~()?]/g,""));
    const dist = getWbDistractors(targetWords, false);
    const words = shuffle([...targetWords, ...dist]);
    qList.push({
      id: `u${unitId}l${lessonId}_ex${exId}_wb_4`,
      type: "word-bank",
      prompt: "Cümlenin İngilizce karşılığını oluşturun:",
      translation: s.tr,
      words: words,
      correctOrder: targetWords,
      enSentence: s.en,
      isEngToTr: false
    });
  }

  // 4. Translation Text (4 questions)
  {
    const s = slice[12];
    qList.push({
      id: `u${unitId}l${lessonId}_ex${exId}_tx_0`,
      type: "translation-text",
      prompt: `"${s.en}" ifadesini Türkçe'ye çevirin:`,
      correctSentence: s.tr,
      enSentence: s.en,
      isEngToTr: true
    });
  }
  {
    const s = slice[13];
    qList.push({
      id: `u${unitId}l${lessonId}_ex${exId}_tx_1`,
      type: "translation-text",
      prompt: `"${s.en}" ifadesini Türkçe'ye çevirin:`,
      correctSentence: s.tr,
      enSentence: s.en,
      isEngToTr: true
    });
  }
  {
    const s = slice[14];
    const targetWords = s.en.split(/\s+/).map(w => w.replace(/[.,\/#!$%\^&\*;:{}=\-_`~()?]/g,""));
    const dist = getWbDistractors(targetWords, false);
    const words = shuffle([...targetWords, ...dist]);
    qList.push({
      id: `u${unitId}l${lessonId}_ex${exId}_wb_5`,
      type: "word-bank",
      prompt: "Cümlenin İngilizce karşılığını oluşturun:",
      translation: s.tr,
      words: words,
      correctOrder: targetWords,
      enSentence: s.en,
      isEngToTr: false
    });
  }
  {
    const s = slice[5];
    const targetWords = s.en.split(/\s+/).map(w => w.replace(/[.,\/#!$%\^&\*;:{}=\-_`~()?]/g,""));
    const dist = getWbDistractors(targetWords, false);
    const words = shuffle([...targetWords, ...dist]);
    qList.push({
      id: `u${unitId}l${lessonId}_ex${exId}_wb_6`,
      type: "word-bank",
      prompt: "Cümlenin İngilizce karşılığını oluşturun:",
      translation: s.tr,
      words: words,
      correctOrder: targetWords,
      enSentence: s.en,
      isEngToTr: false
    });
  }

  return {
    id: `u${unitId}l${lessonId}ex${exId}`,
    title: `Alıştırma ${exId}: Yapı Çalışması`,
    description: `Eşleştirme, Seçmeli, Sıralama ve Çeviri Paketleri (${offset + 1}-${offset + 15})`,
    questions: qList
  };
}

const unit13BaseTranslations = {
  "define": "tanımlamak",
  "abandon": "vazgeçmek",
  "inspect": "denetlemek",
  "specify": "belirtmek",
  "advocate": "savunmak",
  "derive": "türetmek",
  "anticipate": "öngörmek",
  "trigger": "tetiklemek",
  "clarify": "açıklığa kavuşturmak",
  "suspend": "askıya almak",
  "expand": "genişlemek",
  "modify": "değiştirmek",
  "conduct": "yürütmek",
  "terminate": "sonlandırmak",
  "stabilize": "dengelemek",
  "process": "işlemek",
  "restrict": "sınırlandırmak",
  "alter": "değiştirmek",
  "expose": "ifşa etmek",
  "induce": "yol açmak",
  "accumulate": "biriktirmek",
  "protect": "korumak",
  "allocate": "tahsis etmek",
  "shift": "değiştirmek",
  "maximize": "maksimize etmek",
  "integrate": "entegre etmek",
  "detect": "tespit etmek",
  "calculate": "hesaplamak",
  "manipulate": "manipüle etmek"
};

function getUniqueMatchingPairs(allSentences, primaryPool, count, unitId, excludeWords = new Set()) {
  const pairs = [];
  const seenWords = new Set(excludeWords);
  const seenTrs = new Set();
  const addedWords = new Set();

  const getEnglishRoot = (w) => {
    const word = w.toLowerCase().trim();
    if (typeof wordDictionary === 'undefined') return word;
    if (wordDictionary[word]) return word;

    // Plurals / singulars
    if (word.endsWith('s')) {
      const singular = word.slice(0, -1);
      if (wordDictionary[singular]) return singular;
      if (word.endsWith('es')) {
        const singularEs = word.slice(0, -2);
        if (wordDictionary[singularEs]) return singularEs;
      }
    }

    // Past tense -ed
    if (word.endsWith('ed')) {
      const stem1 = word.slice(0, -1); // strip 'd'
      if (wordDictionary[stem1]) return stem1;
      const stem2 = word.slice(0, -2); // strip 'ed'
      if (wordDictionary[stem2]) return stem2;
      if (word.endsWith('ied')) {
        const stem3 = word.slice(0, -3) + 'y';
        if (wordDictionary[stem3]) return stem3;
      }
      if (word.match(/[bcdfghjklmnpqrstvwxyz]\2ed$/)) {
        const stem4 = word.slice(0, -3);
        if (wordDictionary[stem4]) return stem4;
      }
    }

    // Present participle -ing
    if (word.endsWith('ing')) {
      const stem1 = word.slice(0, -3);
      if (wordDictionary[stem1]) return stem1;
      const stem2 = word.slice(0, -3) + 'e';
      if (wordDictionary[stem2]) return stem2;
      if (word.endsWith('ying')) {
        const stem3 = word.slice(0, -4) + 'y';
        if (wordDictionary[stem3]) return stem3;
      }
      if (word.match(/[bcdfghjklmnpqrstvwxyz]\2ing$/)) {
        const stem4 = word.slice(0, -4);
        if (wordDictionary[stem4]) return stem4;
      }
    }

    // Common irregular verbs
    const irregulars = {
      "taken": "take",
      "took": "take",
      "chosen": "choose",
      "chose": "choose",
      "spent": "spend",
      "got": "get",
      "done": "do",
      "did": "do",
      "made": "make",
      "written": "write",
      "wrote": "write",
      "read": "read",
      "built": "build",
      "shown": "show",
      "held": "hold",
      "drawn": "draw",
      "drew": "draw",
      "begun": "begin",
      "began": "begin"
    };
    if (irregulars[word]) return irregulars[word];

    return word;
  };

  const getBaseTr = (w) => {
    // Check specific unit dictionaries first if they are defined
    if (unitId === 13 && typeof unitAra1BaseTranslations !== 'undefined') return unitAra1BaseTranslations[w] || null;
    if (unitId === 17 && typeof unitAra2BaseTranslations !== 'undefined') return unitAra2BaseTranslations[w] || null;
    if (unitId === 14 && typeof unit13BaseTranslations !== 'undefined') return unit13BaseTranslations[w] || null;
    
    // Global wordDictionary lookup
    const rootWord = getEnglishRoot(w);
    if (typeof wordDictionary !== 'undefined' && wordDictionary[rootWord]) {
      const raw = wordDictionary[rootWord];
      const clean = raw.split(',')[0].split('/')[0].split(';')[0].split('(')[0].trim();
      if (clean) return clean;
    }
    return null;
  };

  const getBaseEng = (w) => {
    if (unitId === 13 && typeof unitAra1BaseEnglish !== 'undefined') return unitAra1BaseEnglish[w] || w;
    if (unitId === 17 && typeof unitAra2BaseEnglish !== 'undefined') return unitAra2BaseEnglish[w] || w;
    return getEnglishRoot(w);
  };

  const getMatchingWord = (s) => {
    if (unitId === 27) {
      const tagIndex = s.en.indexOf('<span');
      if (tagIndex !== -1) {
        const prefix = s.en.substring(0, tagIndex).trim();
        const suffix = s.en.substring(tagIndex);
        const prefixWords = prefix.split(/\s+/);
        const noun = prefixWords[prefixWords.length - 1].replace(/[.,\/#!$%\^&\*;:{}=\-_`~()?]/g,"");
        const cleanSuffix = suffix.replace(/<[^>]+>/g, '').replace(/[.,\/#!$%\^&\*;:{}=\-_`~()?]/g,"").trim();
        const cleanSuffixWords = cleanSuffix.split(/\s+/).filter(w => w !== '-');
        const slicedSuffix = cleanSuffixWords.slice(0, 4).join(' ');
        return (noun + ' ' + slicedSuffix).trim();
      }
    }
    return getBaseEng(s.word);
  };

  // First try primaryPool (e.g. current slice)
  for (const s of primaryPool) {
    if (pairs.length >= count) break;
    const rawWord = s.word;
    if (!rawWord) continue;
    const word = getMatchingWord(s);
    const tr = getBaseTr(rawWord) || s.trWord;
    if (!seenWords.has(word) && !seenTrs.has(tr)) {
      seenWords.add(word);
      seenTrs.add(tr);
      addedWords.add(word);
      pairs.push({ left: tr, right: word });
    }
  }

  // Next try allSentences
  if (pairs.length < count) {
    for (const s of allSentences) {
      if (pairs.length >= count) break;
      const rawWord = s.word;
      if (!rawWord) continue;
      const word = getMatchingWord(s);
      const tr = getBaseTr(rawWord) || s.trWord;
      if (!seenWords.has(word) && !seenTrs.has(tr)) {
        seenWords.add(word);
        seenTrs.add(tr);
        addedWords.add(word);
        pairs.push({ left: tr, right: word });
      }
    }
  }

  // Fallback if still not enough (relaxing seenWords/seenTrs check, but trying to keep left/right unique in the returned array)
  if (pairs.length < count) {
    for (const s of primaryPool) {
      if (pairs.length >= count) break;
      const rawWord = s.word;
      if (!rawWord) continue;
      const word = getMatchingWord(s);
      const tr = getBaseTr(rawWord) || s.trWord;
      if (!addedWords.has(word)) {
        addedWords.add(word);
        pairs.push({ left: tr, right: word });
      }
    }
  }

  return pairs;
}

function buildCustom10QuestionExercises(sentences, unitId, lessonId, exId, offset) {
  const qList = [];
  const shuffle = (arr) => [...arr].sort(() => 0.5 - Math.random());
  
  const slice = [];
  for (let i = 0; i < 10; i++) {
    const idx = (offset + i) % sentences.length;
    slice.push(sentences[idx]);
  }

  // 1. Matching (2 questions)
  const match1Pairs = getUniqueMatchingPairs(sentences, slice, 4, unitId);
  qList.push({
    id: `u${unitId}l${lessonId}_ex${exId}_match1`,
    type: "matching",
    prompt: "Kelimeleri Türkçe karşılıklarıyla eşleştirin.",
    pairs: match1Pairs
  });

  const match1Words = new Set(match1Pairs.map(p => p.right));
  const match2Pairs = getUniqueMatchingPairs(sentences, slice, 4, unitId, match1Words);
  qList.push({
    id: `u${unitId}l${lessonId}_ex${exId}_match2`,
    type: "matching",
    prompt: "Kelimeleri Türkçe karşılıklarıyla eşleştirin.",
    pairs: match2Pairs
  });

  const getMcDistractors = (s, isTr) => {
    const targetVal = isTr ? s.tr : s.en;
    const distractors = [];
    const verb = s.word;
    const trVerb = s.trWord;

    if (!isTr && verb && s.en.includes(verb)) {
      const parts = s.en.split(verb);
      if (parts.length === 2) {
        const subj = parts[0].trim();
        let obj = parts[1].trim();
        const hasPeriod = obj.endsWith(".");
        if (hasPeriod) obj = obj.slice(0, -1).trim();

        // 1. Swap Subject and Object (Semantic Reversal)
        const cap = str => str.charAt(0).toUpperCase() + str.slice(1);
        const decap = str => str.charAt(0).toLowerCase() + str.slice(1);
        if (subj.toLowerCase() !== obj.toLowerCase()) {
          const swapped = cap(obj) + " " + verb + " " + decap(subj) + (hasPeriod ? "." : "");
          if (swapped !== s.en && !distractors.includes(swapped)) {
            distractors.push(swapped);
          }
        }

        // 2. Alter word order of Subject if complex (length >= 3 words)
        const subjWords = subj.split(/\s+/);
        if (subjWords.length >= 3) {
          const idx = subjWords.length > 3 ? 2 : 1;
          const temp = subjWords[idx];
          subjWords[idx] = subjWords[idx+1];
          subjWords[idx+1] = temp;
          const alteredSubj = subjWords.join(" ");
          const distVal = alteredSubj + " " + verb + " " + obj + (hasPeriod ? "." : "");
          if (distVal !== s.en && !distractors.includes(distVal)) {
            distractors.push(distVal);
          }
        }

        // 3. Alter word order of Object if complex
        const objWords = obj.split(/\s+/);
        if (objWords.length >= 3) {
          const idx = objWords.length > 3 ? 2 : 1;
          const temp = objWords[idx];
          objWords[idx] = objWords[idx+1];
          objWords[idx+1] = temp;
          const alteredObj = objWords.join(" ");
          const distVal = subj + " " + verb + " " + alteredObj + (hasPeriod ? "." : "");
          if (distVal !== s.en && !distractors.includes(distVal)) {
            distractors.push(distVal);
          }
        }
      }
    }

    if (isTr && trVerb && s.tr.includes(trVerb)) {
      const parts = s.tr.split(trVerb);
      if (parts.length === 2) {
        const prefix = parts[0].trim();
        const suffix = parts[1].trim();
        const words = prefix.split(/\s+/);
        if (words.length >= 3) {
          const temp = words[1];
          words[1] = words[2];
          words[2] = temp;
          const alteredPrefix = words.join(" ");
          const distVal = alteredPrefix + " " + trVerb + (suffix ? " " + suffix : "");
          if (distVal !== s.tr && !distractors.includes(distVal)) {
            distractors.push(distVal);
          }
        }
        if (words.length >= 4) {
          const words2 = prefix.split(/\s+/);
          const temp = words2[2];
          words2[2] = words2[3];
          words2[3] = temp;
          const alteredPrefix = words2.join(" ");
          const distVal = alteredPrefix + " " + trVerb + (suffix ? " " + suffix : "");
          if (distVal !== s.tr && !distractors.includes(distVal)) {
            distractors.push(distVal);
          }
        }
      }
    }

    // 4. Fill remaining spots with Verb Substitution
    const others = sentences.filter(o => o.word !== s.word && o.trWord !== s.trWord);
    const shuffledOthers = shuffle(others);
    for (let i = 0; i < shuffledOthers.length; i++) {
      if (distractors.length >= 3) break;
      const other = shuffledOthers[i];
      if (isTr) {
        if (s.trWord && other.trWord && s.tr.includes(s.trWord)) {
          const distVal = getTrInflectedReplacement(s.tr, s.trWord, other.trWord);
          if (distVal !== s.tr && !distractors.includes(distVal)) {
            distractors.push(distVal);
          }
        }
      } else {
        if (s.word && other.word && s.en.includes(s.word)) {
          const distVal = s.en.replace(s.word, other.word);
          if (distVal !== s.en && !distractors.includes(distVal)) {
            distractors.push(distVal);
          }
        }
      }
    }

    // 5. Fallback
    if (distractors.length < 3) {
      const list = sentences.filter(item => (isTr ? item.tr : item.en) !== targetVal).map(item => isTr ? item.tr : item.en);
      const shuffled = shuffle([...new Set(list)]);
      for (const val of shuffled) {
        if (!distractors.includes(val)) {
          distractors.push(val);
        }
        if (distractors.length >= 3) break;
      }
    }

    while (distractors.length < 3) {
      distractors.push(isTr ? "deneme" : "test");
    }

    return distractors.slice(0, 3);
  };

  const getWbDistractors = (targetWords, isTr) => {
    const list = sentences.map(s => (isTr ? s.tr : s.en).replace(/<[^>]+>/g, '').split(/\s+/).map(w => w.replace(/[.,\/#!$%\^&\*;:{}=\-_`~()?]/g,""))).flat();
    const unique = [...new Set(list)].filter(w => !targetWords.includes(w));
    const shuffled = shuffle(unique);
    while (shuffled.length < 3) {
      shuffled.push(isTr ? "ve" : "the");
    }
    return shuffled.slice(0, 3);
  };

  // 2. Multiple Choice (2 questions)
  {
    const s = slice[8];
    const dist = getMcDistractors(s, true);
    const options = shuffle([s.tr, ...dist]);
    qList.push({
      id: `u${unitId}l${lessonId}_ex${exId}_mc_0`,
      type: "multiple-choice",
      prompt: `"${s.en}" cümlesinin Türkçe karşılığı hangisidir?`,
      options: options,
      correctIndex: options.indexOf(s.tr),
      enSentence: s.en,
      isEngToTr: true
    });
  }
  {
    const s = slice[9];
    const dist = getMcDistractors(s, false);
    const options = shuffle([s.en, ...dist]);
    qList.push({
      id: `u${unitId}l${lessonId}_ex${exId}_mc_1`,
      type: "multiple-choice",
      prompt: `"${s.tr}" cümlesinin İngilizce karşılığı hangisidir?`,
      options: options,
      correctIndex: options.indexOf(s.en),
      enSentence: s.en,
      isEngToTr: false
    });
  }

  // 3. Word Bank (3 questions)
  {
    const s = slice[0];
    const targetWords = s.tr.replace(/<[^>]+>/g, '').split(/\s+/).map(w => w.replace(/[.,\/#!$%\^&\*;:{}=\-_`~()?]/g,""));
    const dist = getWbDistractors(targetWords, true);
    const words = shuffle([...targetWords, ...dist]);
    qList.push({
      id: `u${unitId}l${lessonId}_ex${exId}_wb_0`,
      type: "word-bank",
      prompt: "Cümlenin Türkçe karşılığını oluşturun:",
      translation: s.en,
      words: words,
      correctOrder: targetWords,
      enSentence: s.en,
      isEngToTr: true
    });
  }
  {
    const s = slice[1];
    const targetWords = s.tr.replace(/<[^>]+>/g, '').split(/\s+/).map(w => w.replace(/[.,\/#!$%\^&\*;:{}=\-_`~()?]/g,""));
    const dist = getWbDistractors(targetWords, true);
    const words = shuffle([...targetWords, ...dist]);
    qList.push({
      id: `u${unitId}l${lessonId}_ex${exId}_wb_1`,
      type: "word-bank",
      prompt: "Cümlenin Türkçe karşılığını oluşturun:",
      translation: s.en,
      words: words,
      correctOrder: targetWords,
      enSentence: s.en,
      isEngToTr: true
    });
  }
  {
    const s = slice[2];
    const targetWords = s.en.replace(/<[^>]+>/g, '').split(/\s+/).map(w => w.replace(/[.,\/#!$%\^&\*;:{}=\-_`~()?]/g,""));
    const dist = getWbDistractors(targetWords, false);
    const words = shuffle([...targetWords, ...dist]);
    qList.push({
      id: `u${unitId}l${lessonId}_ex${exId}_wb_2`,
      type: "word-bank",
      prompt: "Cümlenin İngilizce karşılığını oluşturun:",
      translation: s.tr,
      words: words,
      correctOrder: targetWords,
      enSentence: s.en,
      isEngToTr: false
    });
  }
  {
    const s = slice[5];
    const targetWords = s.en.replace(/<[^>]+>/g, '').split(/\s+/).map(w => w.replace(/[.,\/#!$%\^&\*;:{}=\-_`~()?]/g,""));
    const dist = getWbDistractors(targetWords, false);
    const words = shuffle([...targetWords, ...dist]);
    qList.push({
      id: `u${unitId}l${lessonId}_ex${exId}_wb_3`,
      type: "word-bank",
      prompt: "Cümlenin İngilizce karşılığını oluşturun:",
      translation: s.tr,
      words: words,
      correctOrder: targetWords,
      enSentence: s.en,
      isEngToTr: false
    });
  }

  // 4. Translation Text (2 questions)
  {
    const s = slice[3];
    qList.push({
      id: `u${unitId}l${lessonId}_ex${exId}_tx_0`,
      type: "translation-text",
      prompt: `"${s.en}" ifadesini Türkçe'ye çevirin:`,
      correctSentence: s.tr,
      enSentence: s.en,
      isEngToTr: true
    });
  }
  {
    const s = slice[4];
    qList.push({
      id: `u${unitId}l${lessonId}_ex${exId}_tx_1`,
      type: "translation-text",
      prompt: `"${s.en}" ifadesini Türkçe'ye çevirin:`,
      correctSentence: s.tr,
      enSentence: s.en,
      isEngToTr: true
    });
  }

  return {
    id: `u${unitId}l${lessonId}ex${exId}`,
    title: `Alıştırma ${exId}: Yapı Çalışması`,
    description: `Eşleştirme, Seçmeli, Sıralama ve Çeviri Paketleri (${offset + 1}-${offset + 10})`,
    questions: qList
  };
}


function buildAra3ExercisesForLesson67(unitId, lessonId) {
  const exercises = [
    ...buildAra3Exercises(unitAra3Lesson1SentencesRaw, unitId, lessonId),
    ...buildAra3Exercises(unitAra3Lesson2SentencesRaw, unitId, lessonId),
    ...buildAra3Exercises(unitAra3Lesson3SentencesRaw, unitId, lessonId),
    ...buildAra3Exercises(unitAra3Lesson4SentencesRaw, unitId, lessonId)
  ];
  
  exercises.forEach((ex, idx) => {
    const exNum = idx + 1;
    ex.id = `u${unitId}l${lessonId}ex${exNum}`;
    ex.title = ex.title.replace(/^Alıştırma \d+/, `Alıştırma ${exNum}`);
    
    if (Array.isArray(ex.questions)) {
      ex.questions.forEach(q => {
        q.id = q.id + `_ex${exNum}`;
      });
    }
  });
  
  return exercises;
}


function buildAra3Exercises(sentences, unitId, lessonId) {
  const shuffle = (arr) => [...arr].sort(() => 0.5 - Math.random());

  // Greedy interleaving algorithm to prevent consecutive identical question types
  const interleaveQuestions = (questions) => {
    if (questions.length <= 1) return questions;
    const buckets = {};
    questions.forEach(q => {
      if (!buckets[q.type]) buckets[q.type] = [];
      buckets[q.type].push(q);
    });
    const result = [];
    let lastType = null;
    while (true) {
      let bestType = null;
      let maxCount = 0;
      for (let type in buckets) {
        if (type !== lastType && buckets[type].length > maxCount) {
          maxCount = buckets[type].length;
          bestType = type;
        }
      }
      if (!bestType) {
        for (let type in buckets) {
          if (buckets[type].length > maxCount) {
            maxCount = buckets[type].length;
            bestType = type;
          }
        }
      }
      if (!bestType || buckets[bestType].length === 0) break;
      const q = buckets[bestType].shift();
      result.push(q);
      lastType = q.type;
      if (buckets[bestType].length === 0) delete buckets[bestType];
    }
    return result;
  };

  const buildMCQuestion = (s, id) => {
    const tr = s.tr;
    const candidates = sentences.filter(item => item.tr !== tr);
    
    let d1 = tr.replace(/önce/g, "sonra").replace(/öncesinde/g, "sonrasında");
    let d2 = tr.replace(/edilmeden/g, "edildikten").replace(/yapılmadan/g, "yapıldıktan");
    
    const rawDistractors = [];
    if (d1 !== tr) rawDistractors.push(d1);
    if (d2 !== tr) rawDistractors.push(d2);
    
    const distractorsSet = new Set(rawDistractors.filter(d => d !== tr));
    
    if (candidates.length > 0) {
      const candidateList = shuffle(candidates);
      for (let c of candidateList) {
        if (distractorsSet.size >= 3) break;
        distractorsSet.add(c.tr);
      }
    }
    
    const distractors = Array.from(distractorsSet);
    const choices = shuffle([tr, ...distractors]);
    return {
      id: id,
      type: "multiple-choice",
      prompt: `Cümlenin en uygun Türkçe karşılığını seçin:<br><br><strong>"${s.en}"</strong>`,
      options: choices,
      correctIndex: choices.indexOf(tr),
      isEngToTr: true,
      enSentence: s.en
    };
  };
  
  const yalinSentences = sentences.filter(s => !s.en.includes(','));
  const akademikSentences = sentences.filter(s => s.en.includes(','));
  
  const baseList1 = [];
  const finalList1 = [];
  
  // ==========================================
  // EXERCISE 1: Kelime Isınma & Cümle Kurma (Yalın)
  // ==========================================
  // Q1: Matching vocab (first 5 unique word pairs)
  const vocabPairs1 = [];
  const seenWords = new Set();
  for (let s of sentences) {
    if (vocabPairs1.length >= 5) break;
    if (s.word && s.trWord && !seenWords.has(s.word)) {
      seenWords.add(s.word);
      vocabPairs1.push({ left: s.trWord, right: s.word });
    }
  }
  baseList1.push({
    id: `u${unitId}l${lessonId}_ex1_match1`,
    type: "matching",
    prompt: "Kelimeleri Türkçe karşılıklarıyla eşleştirin.",
    pairs: vocabPairs1
  });
  
  // Q2: Matching vocab (next 5 unique word pairs)
  const vocabPairs2 = [];
  for (let s of sentences) {
    if (vocabPairs2.length >= 5) break;
    if (s.word && s.trWord && !seenWords.has(s.word)) {
      seenWords.add(s.word);
      vocabPairs2.push({ left: s.trWord, right: s.word });
    }
  }
  if (vocabPairs2.length > 0) {
    baseList1.push({
      id: `u${unitId}l${lessonId}_ex1_match2`,
      type: "matching",
      prompt: "Kelimeleri Türkçe karşılıklarıyla eşleştirin.",
      pairs: vocabPairs2
    });
  }
  
  // Yalın Cümleler (0-3 -> Word Bank, 4-7 -> MC)
  yalinSentences.slice(0, 4).forEach((s, idx) => {
    const isPast = s.en.includes('debated') || s.en.includes('collapsed') || s.en.includes('investigated') || s.en.includes('responded') || s.en.includes('expanded') || s.en.includes('evolved') || s.en.includes('shifted') || s.en.includes('intervened') || s.en.includes('started') || s.en.includes('concluded') || s.en.includes('had') || s.en.includes('was') || s.en.includes('were') || s.en.includes('been');
    const distractors = isPast ? ["is", "had", "was"] : ["was", "has", "did"];
    const allWords = shuffle([...s.blocks, ...distractors]);
    baseList1.push({
      id: `u${unitId}l${lessonId}_ex1_wb_${idx}`,
      type: "word-bank",
      prompt: "Cümle bloklarını doğru sıraya koyarak İngilizce cümleyi oluşturun:",
      translation: s.tr,
      words: allWords,
      correctOrder: s.blocks,
      enSentence: s.en,
      isEngToTr: false
    });
  });

  yalinSentences.slice(4, 8).forEach((s, idx) => {
    baseList1.push(buildMCQuestion(s, `u${unitId}l${lessonId}_ex1_mc_${idx}`));
  });

  // Last 2 Yalın Cümleler (8-9 -> Keyboard Translation)
  const translationList1 = [];
  yalinSentences.slice(8, 10).forEach((s, idx) => {
    translationList1.push({
      id: `u${unitId}l${lessonId}_ex1_trans_${idx}`,
      type: "translation-text",
      prompt: `"${s.en}" ifadesini Türkçe'ye çevirin:`,
      enSentence: s.en,
      correctSentence: s.tr,
      isEngToTr: true
    });
  });
  
  // ==========================================
  // EXERCISE 2: Dil Bilgisi & Zaman Uyumu (Cloze Test)
  // ==========================================
  const baseList2 = [];
  const translationList2 = [];
  
  // Q1-Q10: Cloze Test on 10 Academic sentences
  akademikSentences.forEach((s, idx) => {
    let options = [];
    if (s.word === "valid") {
      options = ["is", "was", "are", "had been"];
    } else if (s.word === "available") {
      options = ["is", "was", "are", "had been"];
    } else if (s.word === "fluctuate") {
      options = ["fluctuates", "fluctuated", "is fluctuating", "fluctuate"];
    } else if (s.word === "emerge") {
      options = ["emerges", "emerged", "is emerging", "emerge"];
    } else if (s.word === "decline") {
      options = ["declines", "declined", "is declining", "decline"];
    } else if (s.word === "expand") {
      options = ["expands", "expanded", "is expanding", "expand"];
    } else if (s.word === "obvious") {
      options = ["is", "was", "are", "be"];
    } else if (s.word === "complex") {
      options = ["is", "was", "are", "be"];
    } else if (s.word === "function") {
      options = ["functions", "functioned", "is functioning", "function"];
    } else if (s.word === "vary") {
      options = ["varies", "varied", "is varying", "vary"];
    } else if (s.word === "debate") {
      options = ["debated", "debate", "are debating", "had debated"];
    } else if (s.word === "collapse") {
      options = ["collapsed", "collapses", "is collapsing", "was collapsed"];
    } else if (s.word === "investigate") {
      options = ["investigated", "investigate", "are investigating", "have investigated"];
    } else if (s.word === "respond") {
      options = ["responded", "respond", "are responding", "responding"];
    } else if (s.word === "evolve") {
      options = ["evolved", "evolves", "is evolving", "evolve"];
    } else if (s.word === "shift") {
      options = ["shifted", "shifts", "is shifting", "shifted"];
    } else if (s.word === "intervene") {
      options = ["intervened", "intervene", "are intervening", "intervening"];
    } else if (s.word === "cooperate") {
      options = ["cooperated", "cooperate", "are cooperating", "cooperating"];
    } else if (s.word === "terminate") {
      options = ["terminated", "terminates", "is terminating", "terminated"];
    } else if (s.word === "conflict") {
      options = ["conflict", "conflicts", "conflicted", "conflicting"];
    } else if (s.word === "conclude") {
      options = ["concluded", "conclude", "concludes", "concluding"];
    } else if (s.word === "predict") {
      options = ["predicted", "predict", "are predicting", "had predicted"];
    } else if (s.word === "accumulate") {
      options = ["accumulated", "accumulate", "is accumulating", "accumulating"];
    } else if (s.word === "mature") {
      options = ["matured", "matures", "is maturing", "mature"];
    } else if (s.word === "transform") {
      options = ["transformed", "transforms", "is transforming", "transform"];
    } else if (s.word === "occur") {
      options = ["occurred", "occurs", "is occurring", "occur"];
    } else if (s.word === "analyze") {
      options = ["analyzed", "analyze", "are analyzing", "analyzing"];
    } else if (s.word === "implement") {
      options = ["implemented", "implement", "is implementing", "implemented"];
    } else if (s.word === "allocate") {
      options = ["allocated", "allocates", "is allocating", "allocated"];
    } else if (s.word === "formulate") {
      options = ["formulated", "formulates", "is formulating", "formulated"];
    } else if (s.word === "publish") {
      options = ["published", "publishes", "is publishing", "published"];
    } else if (s.word === "detect") {
      options = ["detected", "detects", "is detecting", "detected"];
    } else if (s.word === "modify") {
      options = ["modified", "modifies", "is modifying", "modified"];
    } else if (s.word === "distribute") {
      options = ["distributed", "distributes", "is distributing", "distributed"];
    } else if (s.word === "enforce") {
      options = ["enforced", "enforces", "is enforcing", "enforced"];
    } else {
      options = [s.word, s.word + "d", s.word + "s", "is " + s.word];
    }
    
    const correctVal = options[0];
    const shuffledOptions = shuffle(options);
    
    const isFirstType = idx % 2 === 0;
    
    baseList2.push({
      id: `u${unitId}l${lessonId}_ex2_fb_${idx}`,
      type: isFirstType ? "fill-blank-dropdown" : "fill-blank",
      prompt: isFirstType ? "Boşluğa gelecek en uygun kelimeyi seçin:" : "Boşluğu doldur",
      sentence: s.blank,
      options: shuffledOptions,
      correctIndex: shuffledOptions.indexOf(correctVal)
    });
  });
  
  // Q11-Q14: Word Bank on academic sentences 0 to 3 (instead of multiple choice)
  akademikSentences.slice(0, 4).forEach((s, idx) => {
    const distractors = ["is", "had", "was"];
    const allWords = shuffle([...s.blocks, ...distractors]);
    baseList2.push({
      id: `u${unitId}l${lessonId}_ex2_wb_${idx}`,
      type: "word-bank",
      prompt: "Cümle bloklarını doğru sıraya koyarak İngilizce akademik cümleyi oluşturun:",
      translation: s.tr,
      words: allWords,
      correctOrder: s.blocks,
      enSentence: s.en,
      isEngToTr: false
    });
  });
  
  // Last 1 Academic sentence as Keyboard Translation
  const lastMcAcad = akademikSentences[4];
  translationList2.push({
    id: `u${unitId}l${lessonId}_ex2_trans_last`,
    type: "translation-text",
    prompt: `"${lastMcAcad.en}" ifadesini Türkçe'ye çevirin:`,
    enSentence: lastMcAcad.en,
    correctSentence: lastMcAcad.tr,
    isEngToTr: true
  });
  
  // ==========================================
  // EXERCISE 3: Akademik Okuma & Cümle Eşleştirme (Halves)
  // ==========================================
  const baseList3 = [];
  
  // Q1: Match the Halves 1 (first 5 Academic sentences)
  const halvesPairs1 = [];
  akademikSentences.slice(0, 5).forEach(s => {
    const parts = s.en.split(',');
    if (parts.length >= 2) {
      halvesPairs1.push({
        left: parts[0].trim() + ",",
        right: parts.slice(1).join(',').trim()
      });
    }
  });
  baseList3.push({
    id: `u${unitId}l${lessonId}_ex3_halves1`,
    type: "matching",
    prompt: "Aşağıdaki cümle yarılarını anlamlı olacak şekilde eşleştirin.",
    leftHeader: "Yan Cümle (Before...)",
    rightHeader: "Ana Cümle",
    pairs: halvesPairs1
  });
  
  // Q2: Match the Halves 2 (second 5 Academic sentences)
  const halvesPairs2 = [];
  akademikSentences.slice(5, 10).forEach(s => {
    const parts = s.en.split(',');
    if (parts.length >= 2) {
      halvesPairs2.push({
        left: parts[0].trim() + ",",
        right: parts.slice(1).join(',').trim()
      });
    }
  });
  baseList3.push({
    id: `u${unitId}l${lessonId}_ex3_halves2`,
    type: "matching",
    prompt: "Aşağıdaki cümle yarılarını anlamlı olacak şekilde eşleştirin.",
    leftHeader: "Yan Cümle (Before...)",
    rightHeader: "Ana Cümle",
    pairs: halvesPairs2
  });
  
  // Akademik Cümleler (0-7 -> Word Bank)
  akademikSentences.slice(0, 8).forEach((s, idx) => {
    const distractors = ["is", "had", "was"];
    const allWords = shuffle([...s.blocks, ...distractors]);
    baseList3.push({
      id: `u${unitId}l${lessonId}_ex3_wb_${idx}`,
      type: "word-bank",
      prompt: "Cümle bloklarını doğru sıraya koyarak İngilizce akademik cümleyi oluşturun:",
      translation: s.tr,
      words: allWords,
      correctOrder: s.blocks,
      enSentence: s.en,
      isEngToTr: false
    });
  });

  // Last 2 Academic sentences (8-9 -> Keyboard Translation)
  const translationList3 = [];
  akademikSentences.slice(8, 10).forEach((s, idx) => {
    translationList3.push({
      id: `u${unitId}l${lessonId}_ex3_trans_${idx}`,
      type: "translation-text",
      prompt: `"${s.en}" ifadesini Türkçe'ye çevirin:`,
      enSentence: s.en,
      correctSentence: s.tr,
      isEngToTr: true
    });
  });
  
  return [
    {
      id: `u${unitId}l${lessonId}ex1`,
      title: "Alıştırma 1: Kelime Isınma & Cümle Kurma (Yalın)",
      description: "Kelime eşleştirme kartları ve 10 yalın cümlenin söz dizimi (Word Bank)",
      questions: [...interleaveQuestions(baseList1), ...translationList1]
    },
    {
      id: `u${unitId}l${lessonId}ex2`,
      title: "Alıştırma 2: Dil Bilgisi & Zaman Uyumu (Cloze Test)",
      description: "Çoktan seçmeli boşluk doldurma ve çoktan seçmeli cümle çevirileri",
      questions: [...interleaveQuestions(baseList2), ...translationList2]
    },
    {
      id: `u${unitId}l${lessonId}ex3`,
      title: "Alıştırma 3: Akademik Okuma & Cümle Eşleştirme (Halves)",
      description: "Cümle yarılarını birleştirme ve akademik düzey blok sıralama",
      questions: [...interleaveQuestions(baseList3), ...translationList3]
    }
  ];
}

