  { en: "Core infrastructure nodes must upgrade systems <span style=\"color: #ff6b6b; font-weight: bold;\">whose</span> cryptographic tokens validate entries automatically to block unauthorized client traces.", tr: "Çekirdek altyapı düğümleri, yetkisiz istemci izlerini otomatik olarak engellemek için kriptografik belirteçleri girişleri doğrulayan sistemleri yükseltmelidir.", word: "whose", trWord: "kriptografik belirteçleri girişleri doğrulayan", blank: "Core infrastructure nodes must upgrade systems ___ cryptographic tokens validate entries automatically to block unauthorized client traces.", options: ["whose", "who", "which", "whom"] },
  { en: "Technicians must safely isolate organic chemical compounds <span style=\"color: #ff6b6b; font-weight: bold;\">whose</span> unstable structures produce explosive exothermic reactions under direct sunlight exposure.", tr: "Teknisyenler, doğrudan güneş ışığına maruz kaldığında kararsız yapıları patlayıcı ekzotermik reaksiyonlar üreten organik kimyasal bileşikleri güvenli bir şekilde izole etmelidir.", word: "whose", trWord: "kararsız yapıları patlayıcı reaksiyonlar üreten", blank: "Technicians must safely isolate organic chemical compounds ___ unstable structures produce explosive exothermic reactions under direct sunlight exposure.", options: ["whose", "who", "which", "whom"] },
  { en: "Discerning firms choose software architects <span style=\"color: #ff6b6b; font-weight: bold;\">whose</span> adaptive builds minimize navigation lag thresholds, enhancing user performance metrics significantly.", tr: "Seçici firmalar, kullanıcı performansı metriklerini önemli ölçüde artıran, uyarlanabilir sürümleri gezinme gecikmesi sınırlarını en aza indiren yazılım mimarlarını seçer.", word: "whose", trWord: "uyarlanabilir sürümleri gecikmeyi en aza indiren", blank: "Discerning firms choose software architects ___ adaptive builds minimize navigation lag thresholds, enhancing user performance metrics significantly.", options: ["whose", "who", "which", "whom"] },
  { en: "Development leaders reward agile frontend developers <span style=\"color: #ff6b6b; font-weight: bold;\">whose</span> clean source code handles complex server queries seamlessly over weekends.", tr: "Geliştirme liderleri, hafta sonları karmaşık sunucu sorgularını sorunsuz bir şekilde yöneten, temiz kaynak kodları sorguları işleyen çevik ön uç geliştiricilerini ödüllendirir.", word: "whose", trWord: "kaynak kodları sorguları işleyen", blank: "Development leaders reward agile frontend developers ___ source code handles complex server queries seamlessly over weekends.", options: ["whose", "who", "which", "whom"] },
  { en: "Field crews must repair unreinforced structures <span style=\"color: #ff6b6b; font-weight: bold;\">whose</span> concrete columns experienced physical degradation during seismic simulation stress checks.", tr: "Saha ekipleri, sismik simülasyon stres kontrolleri sırasında beton kolonları fiziksel bozulma yaşayan güçlendirilmemiş yapıları onarmalıdır.", word: "whose", trWord: "beton kolonları fiziksel bozulma yaşayan", blank: "Field crews must repair unreinforced structures ___ concrete columns experienced physical degradation during seismic simulation stress checks.", options: ["whose", "who", "which", "whom"] },
  { en: "Automated validation compilers flag relational databases <span style=\"color: #ff6b6b; font-weight: bold;\">whose</span> baseline configurations conflict openly, creating catastrophic execution bottlenecks.", tr: "Otomatik doğrulama derleyicileri, feci yürütme darboğazları yaratarak, referans yapılandırmaları açıkça çelişen ilişkisel veritabanlarını işaretler.", word: "whose", trWord: "referans yapılandırmaları açıkça çelişen", blank: "Automated validation compilers flag relational databases ___ baseline configurations conflict openly, creating catastrophic execution bottlenecks.", options: ["whose", "who", "which", "whom"] }
